  function buyVideo(video) {
    if (!video) return;
    getState().then(async (state) => {
      if (video.access === 'vip' && state.role === 'guest') { toast('This title requires VIP access.', 'error'); return; }
      const purchasedIds = new Set(await getPurchasedVideoIds(state));
      if (state.role === 'vip' || state.role === 'admin') { await unlockVideoForState(state, video); window.dispatchEvent(new CustomEvent('hg:state-changed')); location.href = `video.html?id=${encodeURIComponent(video.id)}`; return; }
      if (purchasedIds.has(String(video.id)) || storage.isUnlockedForUser(state.email, video.id)) { location.href = `video.html?id=${encodeURIComponent(video.id)}`; return; }
      if (state.totalPoints < video.points) { toast(`You need ${video.points - state.totalPoints} more points.`, 'error'); return; }
      try {
        await deductWalletPointsForState(state, video.points, video.title);
        await unlockVideoForState(state, video);
        toast(`${video.title} added to your library.`, 'success');
        window.dispatchEvent(new CustomEvent('hg:state-changed'));
        setTimeout(() => location.href = 'my-library.html', 350);
      } catch (error) {
        toast(extractErrorMessage(error, 'Unable to unlock this video right now.'), 'error');
      }
    });
  }

  async function addPoints(amount, label) {
    const state = await getState();
    if (state.role !== 'admin') {
      toast('Only admins can manually grant points. Guest and VIP points should come from the payment flow.', 'error');
      return false;
    }
    const total = storage.addPoints(amount);
    storage.addTransaction({ type: 'points', label, amount, grantedBy: state.email || 'admin' });
    toast(`${amount} points added. Wallet: ${total} pts`, 'success');
    window.dispatchEvent(new CustomEvent('hg:state-changed'));
    return true;
  }

  function videoPrimaryAction(state, video) {
    if (!canAccessVideo(state.role, video)) return { text: 'Join VIP', href: 'vip-checkout.html', kind: 'link' };
    if (state.role === 'admin' || state.role === 'vip' || storage.isUnlocked(video.id)) return { text: video.videoUrl ? 'Watch Now' : 'Open Video', href: `video.html?id=${video.id}`, kind: 'link' };
    return { text: `Unlock for ${video.points} pts`, href: '#', kind: 'buy' };
  }

  function renderVideoCards(container, videos, state) {
    container.innerHTML = videos.map((video) => {
      const action = videoPrimaryAction(state, video);
      const lockedByVip = !canAccessVideo(state.role, video);
      return `<article class="group overflow-hidden rounded-[1.75rem] border border-white/10 bg-white/5 shadow-xl shadow-black/20 transition hover:-translate-y-1 hover:border-pink-400/30 ${lockedByVip ? 'opacity-80' : ''}"><div class="relative"><img src="${escapeHtml(video.image)}" alt="${escapeHtml(video.title)}" class="h-64 w-full object-cover transition duration-500 group-hover:scale-105" /><div class="absolute inset-0 bg-gradient-to-t from-black/70 via-black/20 to-transparent"></div><span class="absolute left-4 top-4 rounded-full bg-black/60 px-3 py-1 text-xs text-white backdrop-blur">${escapeHtml(video.category)}</span>${lockedByVip ? '<div class="absolute inset-0 flex items-center justify-center bg-black/55 text-sm font-semibold uppercase tracking-[0.2em] text-pink-300">VIP Only</div>' : ''}</div><div class="p-5"><div class="flex items-start justify-between gap-4"><div><h4 class="text-xl font-semibold">${escapeHtml(video.title)}</h4><p class="mt-1 text-sm text-neutral-400">${escapeHtml(video.description)}</p></div><div class="rounded-xl bg-pink-500/10 px-3 py-2 text-right text-sm font-semibold text-pink-300">${video.access === 'vip' ? '<div>VIP</div><div class="text-[11px] text-neutral-400">VIP + admin</div>' : `<div>${video.points} pts</div><div class="text-[11px] text-neutral-400">${moneyFromPoints(video.points)} unlock</div>`}</div></div><div class="mt-5 flex gap-3"><a href="${action.href}" data-video-primary="${video.id}" class="flex-1 rounded-xl bg-pink-500 px-4 py-3 text-center font-medium text-white transition hover:bg-pink-400">${action.text}</a><a href="video.html?id=${video.id}" class="rounded-xl border border-white/15 px-4 py-3 text-sm text-neutral-300 transition hover:bg-white/5">Preview</a></div></div></article>`;
    }).join('');
    container.querySelectorAll('[data-video-primary]').forEach((button) => button.addEventListener('click', (event) => {
      const video = getVideo(button.dataset.videoPrimary);
      const action = videoPrimaryAction(state, video);
      if (action.kind === 'buy') { event.preventDefault(); buyVideo(video); }
    }));
  }

